#include <bits/stdc++.h>
using namespace std;int n;long long W[16][16];long long dp[1<<16][16];const long long INF=1e15;
int main(){cin>>n;for(int i=0;i<n;i++)for(int j=0;j<n;j++)cin>>W[i][j];for(auto&r:dp)for(auto&x:r)x=INF;dp[1][0]=0;for(int m=1;m<(1<<n);m++)for(int u=0;u<n;u++){if(dp[m][u]==INF||!((m>>u)&1))continue;for(int v=0;v<n;v++){if((m>>v)&1||W[u][v]==0)continue;long long&nx=dp[m|(1<<v)][v];nx=min(nx,dp[m][u]+W[u][v]);}}long long ans=INF;for(int u=1;u<n;u++)if(W[u][0])ans=min(ans,dp[(1<<n)-1][u]+W[u][0]);cout<<ans<<"\n";}
